mapper.select:
select s.score_id as scoreId, s.enroll_id as enrollId, s.contest_id as contestId, c.contest_name as contestName, c.category as category, s.score_value as scoreValue, s.score_value as score, s.rank_no as rankNo, s.rank_no as rank, s.award_level as awardLevel, s.remark as remark, s.publish_time as publishTime from jst_score_record s left join jst_contest c on c.contest_id = s.contest_id and c.del_flag = '0' where s.del_flag = '0' and s.user_id = #{userId} and s.publish_status = 'published'
and s.contest_id = #{contestId}
order by s.publish_time desc, s.score_id desc

select er.enroll_id as enrollId, er.contest_id as contestId, c.contest_name as contestName, c.category as category, er.score_value as scoreValue, er.score_value as score, er.award as awardLevel, er.remark as remark, er.publish_time as publishTime from jst_enroll_record er left join jst_contest c on c.contest_id = er.contest_id and c.del_flag = '0' where er.del_flag = '0' and er.user_id = #{userId} and er.score_value is not null
and er.contest_id = #{contestId}
order by er.publish_time desc, er.enroll_id desc

select s.contest_id as contestId, c.contest_name as contestName, c.category as category, s.score_value as scoreValue, s.score_value as score, s.rank_no as rankNo, s.rank_no as rank, s.award_level as awardLevel, s.remark as remark, s.publish_time as publishTime from jst_score_record s left join jst_contest c on c.contest_id = s.contest_id and c.del_flag = '0' left join jst_enroll_record er on er.enroll_id = s.enroll_id and er.del_flag = '0' left join jst_participant p on p.participant_id = s.participant_id and p.del_flag = '0'
s.del_flag = '0' and s.publish_status = 'published'
and s.contest_id = #{contestIdNum}
and c.contest_name like concat('%', #{contestKeyword}, '%')
and p.name = #{name}
and p.guardian_mobile = #{mobile}
and p.id_card_no like concat('%', #{idCard4})
and (p.guardian_mobile = #{keyword} or er.enroll_no = #{keyword})
order by s.publish_time desc, s.score_id desc limit 20

select er.contest_id as contestId, c.contest_name as contestName, c.category as category, er.score_value as scoreValue, er.score_value as score, er.award as awardLevel, er.remark as remark, er.publish_time as publishTime from jst_enroll_record er left join jst_contest c on c.contest_id = er.contest_id and c.del_flag = '0' left join jst_participant p on p.participant_id = er.participant_id and p.del_flag = '0'
er.del_flag = '0' and er.score_value is not null
and er.contest_id = #{contestIdNum}
and c.contest_name like concat('%', #{contestKeyword}, '%')
and p.name = #{name}
and p.guardian_mobile = #{mobile}
and p.id_card_no like concat('%', #{idCard4})
and (p.guardian_mobile = #{keyword} or er.enroll_no = #{keyword})
order by er.publish_time desc, er.enroll_id desc limit 20
